    /**
     * Deterministically generates a highly unique, readable paragraph of approximately 400-600 words
     * based on an ID between 0 and 499.
     */
    fun getParagraph(id: Int): String {
        val seed = id.toLong()
        val random = Random(seed)

        // Select parts
        val topicIdx = id % topics.size
        val introIdx = (id / topics.size) % introTemplates.size
        val body1Idx = (id / (topics.size * introTemplates.size)) % body1Templates.size
        val body2Idx = (id / (topics.size * introTemplates.size * body1Templates.size)) % body2Templates.size
        val conclIdx = (id / (topics.size * introTemplates.size * body1Templates.size * body2Templates.size)) % conclusionTemplates.size

        val intro = introTemplates[introIdx]
        val body1 = body1Templates[body1Idx]
        val body2 = body2Templates[body2Idx]
        val concl = conclusionTemplates[conclIdx]

        // To make it highly unique, we can inject small transitional words or change synonyms dynamically based on seed
        val transitions = listOf(
            "Furthermore, it is critical to observe that ",
            "To illustrate this point further, ",
            "Additionally, we must recognize that ",
            "On a deeper level, ",
            "In light of this, "
        )
        val trans1 = transitions[random.nextInt(transitions.size)]
        val trans2 = transitions[random.nextInt(transitions.size)]

        return "Theme: ${topics[topicIdx]}\n\n$intro\n\n$trans1$body1\n\n$trans2$body2\n\n$concl"
    }
}
